+        .unwrap();
+    assert_eq!(exec.state("ext1"), Some(ContainmentState::Sandboxed));
+    assert_eq!(exec.state("ext2"), Some(ContainmentState::Terminated));
+    assert_eq!(exec.state("ext3"), Some(ContainmentState::Running));
