+#[test]
+fn enrichment_signature_sentinel_is_all_zeros() {
+    assert!(SIGNATURE_SENTINEL.iter().all(|&b| b == 0));
+    assert_eq!(SIGNATURE_SENTINEL.len(), 64);
+}
